// Public catalog of actions the AI may propose. Internal proxy details live
// in the Dispatch Execute node; this catalog is sanitized for external view.
const c = {
  list_alerts: {
    description: 'List all currently pending alerts on the dashboard.',
    risk: 'low',
    readonly: true,
    args_schema: {}
  },
  list_services_down: {
    description: 'List services that are currently down or require authentication.',
    risk: 'low',
    readonly: true,
    args_schema: {}
  },
  get_service_history: {
    description: 'Get uptime, latency, and incidents for one service over the last N hours (default 24).',
    risk: 'low',
    readonly: true,
    args_schema: { name: 'string!', hours: 'number?' },
    example_args: { name: 'Plex', hours: 24 }
  },
  top_blocked_domains: {
    description: 'List the top blocked DNS domains from Pi-hole.',
    risk: 'low',
    readonly: true,
    args_schema: {}
  },
  recent_failed_logins: {
    description: 'List recent Wazuh failed login attempts (broken down by IP, user, agent).',
    risk: 'low',
    readonly: true,
    args_schema: {}
  },
  ack_alerts: {
    description: 'Acknowledge the given alert IDs. They will be removed from the pending list.',
    risk: 'low',
    readonly: false,
    args_schema: { ids: 'string[]!' },
    example_args: { ids: ['zabbix-offline-12345'] }
  }
};

return [{ json: { catalog: c, count: Object.keys(c).length } }];

// Dispatch an action. Validates against the catalog, calls the underlying
// webhook via this.helpers.httpRequest, returns the result + an args_hash for
// the audit trail. Outputs:
//   ok=true:  { ok, action_id, args, args_hash, result, args_json_sql }
//   ok=false: { ok, error, action_id }

const N8N_BASE = 'https://n8n.thisaimachine.com/webhook';

const CATALOG = {
  list_alerts: {
    description: 'List all currently pending alerts on the dashboard.',
    risk: 'low', readonly: true, args_schema: {},
    proxy: { method: 'GET', url: '/alerts/pending' }
  },
  list_services_down: {
    description: 'List services currently in down or auth-required status.',
    risk: 'low', readonly: true, args_schema: {},
    proxy: { method: 'GET', url: '/services/health', filter: 'down_only' }
  },
  get_service_history: {
    description: 'Get uptime/latency history for one service over the last N hours.',
    risk: 'low', readonly: true, args_schema: { name: 'string!', hours: 'number?' },
    proxy: { method: 'GET', url: '/services/history', query_args: ['name', 'hours'] }
  },
  top_blocked_domains: {
    description: 'Top blocked DNS domains from Pi-hole.',
    risk: 'low', readonly: true, args_schema: {},
    proxy: { method: 'GET', url: '/pihole/stats', extract: 'top_blocked' }
  },
  recent_failed_logins: {
    description: 'Recent Wazuh failed login attempts.',
    risk: 'low', readonly: true, args_schema: {},
    proxy: { method: 'GET', url: '/wazuh/failed-logins' }
  },
  ack_alerts: {
    description: 'Acknowledge the given alert IDs.',
    risk: 'low', readonly: false, args_schema: { ids: 'string[]!' },
    proxy: { method: 'POST', url: '/alerts/acknowledge', body_args: ['ids'] }
  }
};

function validateArgs(schema, args) {
  const errors = [];
  for (const [k, spec] of Object.entries(schema)) {
    const required = spec.endsWith('!');
    const baseType = spec.replace(/[!?]$/, '');
    const isArray = baseType.endsWith('[]');
    const elemType = baseType.replace(/\[\]$/, '');
    const v = args?.[k];
    if (v === undefined || v === null) {
      if (required) errors.push(`Missing required arg: ${k}`);
      continue;
    }
    if (isArray) {
      if (!Array.isArray(v)) { errors.push(`${k} must be array`); continue; }
      if (elemType && !v.every(x => typeof x === elemType)) {
        errors.push(`${k} elements must be ${elemType}`);
      }
    } else if (typeof v !== elemType) {
      errors.push(`${k} must be ${elemType}`);
    }
  }
  return errors;
}

function argsHash(args) {
  const sortedKeys = Object.keys(args || {}).sort();
  const canonical = JSON.stringify(args || {}, sortedKeys);
  // 4 parallel DJB2 streams → 64 hex chars. Deterministic, sandbox-safe.
  // Not cryptographic; only used to dedup (action_id, args) pairs.
  let h1 = 5381n, h2 = 7853n, h3 = 9871n, h4 = 11483n;
  const M = 0xffffffffffffffffn;
  for (let i = 0; i < canonical.length; i++) {
    const c = BigInt(canonical.charCodeAt(i));
    h1 = ((h1 << 5n) + h1 + c) & M;
    h2 = ((h2 << 5n) + h2 + c) & M;
    h3 = ((h3 << 5n) + h3 + c) & M;
    h4 = ((h4 << 5n) + h4 + c) & M;
  }
  return [h1, h2, h3, h4].map(h => h.toString(16).padStart(16, '0')).join('');
}

const input = $input.first().json;
const body = input.body || input;
const actionId = body.id;
const args = body.args || {};

const action = CATALOG[actionId];
if (!action) {
  return [{ json: { ok: false, action_id: actionId, error: `Unknown action: ${actionId}` } }];
}
const errs = validateArgs(action.args_schema || {}, args);
if (errs.length) {
  return [{ json: { ok: false, action_id: actionId, error: errs.join('; ') } }];
}

// Build proxy request
const p = action.proxy;
let url = N8N_BASE + p.url;
if (p.query_args) {
  const qs = p.query_args
    .filter(k => args[k] !== undefined)
    .map(k => `${encodeURIComponent(k)}=${encodeURIComponent(args[k])}`)
    .join('&');
  if (qs) url += '?' + qs;
}
const opts = {
  method: p.method,
  url,
  timeout: 10000,
  ignoreHttpStatusErrors: true,
  json: true
};
if (p.body_args) {
  const b = {};
  for (const k of p.body_args) if (args[k] !== undefined) b[k] = args[k];
  opts.body = b;
}

let result;
try {
  result = await this.helpers.httpRequest(opts);
} catch (e) {
  return [{ json: { ok: false, action_id: actionId, error: 'proxy failed: ' + (e?.message || e) } }];
}

// Post-process
if (p.extract) {
  const obj = Array.isArray(result) ? result[0] : result;
  result = obj?.[p.extract] ?? null;
}
if (p.filter === 'down_only') {
  const obj = Array.isArray(result) ? result[0] : result;
  result = (obj?.services || []).filter(s => s.status === 'down' || s.status === 'auth');
}

const hash = argsHash(args);
const argsJsonSql = JSON.stringify(args).replace(/\\/g, '\\\\').replace(/'/g, "''");
const actionIdSql = String(actionId).replace(/'/g, "''");

return [{ json: {
  ok: true,
  action_id: actionId,
  action_id_sql: actionIdSql,
  args,
  args_hash: hash,
  args_json_sql: argsJsonSql,
  result
} }];

// Record a user decision (accepted or dismissed) about a previously-proposed
// action. Frontend calls this on Dismiss; the execute path records 'accepted'
// itself, so this is mostly the dismissal channel.
function argsHash(args) {
  const sortedKeys = Object.keys(args || {}).sort();
  const canonical = JSON.stringify(args || {}, sortedKeys);
  let h1 = 5381n, h2 = 7853n, h3 = 9871n, h4 = 11483n;
  const M = 0xffffffffffffffffn;
  for (let i = 0; i < canonical.length; i++) {
    const c = BigInt(canonical.charCodeAt(i));
    h1 = ((h1 << 5n) + h1 + c) & M;
    h2 = ((h2 << 5n) + h2 + c) & M;
    h3 = ((h3 << 5n) + h3 + c) & M;
    h4 = ((h4 << 5n) + h4 + c) & M;
  }
  return [h1, h2, h3, h4].map(h => h.toString(16).padStart(16, '0')).join('');
}

const input = $input.first().json;
const body = input.body || input;
const actionId = body.action_id;
const args = body.args || {};
const decision = body.decision;

if (!actionId) return [{ json: { ok: false, error: 'action_id required' } }];
if (decision !== 'accepted' && decision !== 'dismissed') {
  return [{ json: { ok: false, error: "decision must be 'accepted' or 'dismissed'" } }];
}

const hash = argsHash(args);
const argsJsonSql = JSON.stringify(args).replace(/\\/g, '\\\\').replace(/'/g, "''");
const actionIdSql = String(actionId).replace(/'/g, "''");

return [{ json: {
  ok: true,
  action_id: actionId,
  action_id_sql: actionIdSql,
  args,
  args_hash: hash,
  args_json_sql: argsJsonSql,
  decision
} }];

const rows = $input.all().map(i => i.json);
const days = Number($('GET /actions/suppressed').first().json.query.days) || 7;

const suppressed = rows.map(r => {
  let parsedArgs = null;
  try { parsedArgs = r.args_json ? JSON.parse(r.args_json) : null; } catch {}
  return {
    action_id: r.action_id,
    args_hash: r.args_hash,
    args: parsedArgs,
    dismissed_at: r.dismissed_at_unix ? new Date(Number(r.dismissed_at_unix) * 1000).toISOString() : null
  };
});

return [{ json: { window_days: days, count: suppressed.length, suppressed } }];
